generated_oml:
// Acting components
instance HeatbedActuator : DTDFVocab:ActingComponent [
    base:desc "Actuator controlling heatbed power via GPIO signals through MOSFETs and optocouplers."
]

instance FanActuator : DTDFVocab:ActingComponent [
    base:desc "Actuator controlling fan speed via GPIO signals through MOSFETs and optocouplers."
]

// Sensing components
instance DS18S20IntSensor1 : DTDFVocab:SensingComponent [
    base:desc "DS18S20 sensor inside the incubator box monitoring one internal air temperature."
    DTDFVocab:producedData TemperatureSensorTelemetryMessage
]

instance DS18S20IntSensor2 : DTDFVocab:SensingComponent [
    base:desc "DS18S20 sensor inside the incubator box monitoring another internal air temperature."
    DTDFVocab:producedData TemperatureSensorTelemetryMessage
]

instance DS18S20ExtSensor : DTDFVocab:SensingComponent [
    base:desc "DS18S20 sensor outside the incubator box for ambient temperature measurement."
    DTDFVocab:producedData TemperatureSensorTelemetryMessage
]

// Data transmitted
instance TemperatureSensorTelemetryMessage : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom DS18S20IntSensor1, DS18S20IntSensor2, DS18S20ExtSensor
]

// Data instances
instance TemperatureTimeSeriesData : DTDFVocab:Data [
    base:desc "Aggregated temperature readings from the three DS18S20 sensors over time."
    DTDFVocab:fromData TemperatureSensorTelemetryMessage
    DTDFVocab:inputTo RabbitMQBroker, SciPyCalibration, PythonController
]

instance ActuatorStateData : DTDFVocab:Data [
    base:desc "Current states of heatbed and fan actuators published alongside sensor data."
    DTDFVocab:fromData TemperatureSensorTelemetryMessage
    DTDFVocab:inputTo PythonController
]

// Models
instance ModelAThermal : DTDFVocab:Model [
    base:desc "Model A: single-state temperature model of the incubator air."
    DTDFVocab:inputTo PythonController
]

instance ModelBThermal : DTDFVocab:Model [
    base:desc "Model B: dual-state model including heatbed temperature."
    DTDFVocab:inputTo PythonController
]

// Enablers
instance RabbitMQBroker : DTDFVocab:Enabler [
    base:desc "RabbitMQ message broker on the Raspberry Pi 4 Model B for sensor data and control messages."
    DTDFVocab:enables MonitoringService
]

instance SciPyCalibration : DTDFVocab:Enabler [
    base:desc "SciPy library performing nonlinear least-squares calibration of thermal model parameters."
    DTDFVocab:enables CalibrationService
]

instance PythonController : DTDFVocab:Enabler [
    base:desc "Python controller consuming sensor data, running simulations, and issuing actuator commands."
    DTDFVocab:enables PredictiveSimulationService, OptimizationService, ControlService
]

// Services
instance MonitoringService : DTDFVocab:Service [
    base:desc "Real-time monitoring of temperature and actuator status from sensor data."
    DTDFVocab:provides RealTimeTemperatureInsight, TemperatureNonUniformityInsight
]

instance PredictiveSimulationService : DTDFVocab:Service [
    base:desc "Predictive simulation of the incubator’s thermal dynamics using Model A and Model B."
    DTDFVocab:provides PredictedThermalBehaviorInsight
]

instance CalibrationService : DTDFVocab:Service [
    base:desc "Model calibration via nonlinear least‑squares optimization."
    DTDFVocab:provides CalibratedParameterValuesInsight
]

instance OptimizationService : DTDFVocab:Service [
    base:desc "Optimization of heating‑period parameters to sustain target temperatures while minimizing energy consumption."
    DTDFVocab:provides OptimizeEnergyConsumptionAction
]

instance ControlService : DTDFVocab:Service [
    base:desc "Actuator control service managing heating and fan duty cycles."
    DTDFVocab:provides AdjustHeatingDutyCycleAction, AdjustFanDutyCycleAction
]

// Insights
instance CalibratedParameterValuesInsight : DTDFVocab:Insight [
    base:desc "Calibrated parameter values (C_air, G_box, G_heater, C_heater) derived from nonlinear least‑squares optimization."
]

instance TemperatureNonUniformityInsight : DTDFVocab:Insight [
    base:desc "Detection of temperature non‑uniformity among internal sensors during incubation."
]

instance PredictedThermalBehaviorInsight : DTDFVocab:Insight [
    base:desc "Predictions of thermal behavior based on Model A and Model B for future temperature evolution."
]

instance RealTimeTemperatureInsight : DTDFVocab:Insight [
    base:desc "Current temperature readings in real‑time from the incubator sensors."
]

// Actions
instance AdjustHeatingDutyCycleAction : DTDFVocab:Action [
    base:desc "Adjusts heating duty cycle to achieve target temperature efficiently."
    DTDFVocab:IsAutomatic true
]

instance AdjustFanDutyCycleAction : DTDFVocab:Action [
    base:desc "Adjusts fan duty cycle based on temperature predictions."
    DTDFVocab:IsAutomatic true
]

instance OptimizeEnergyConsumptionAction : DTDFVocab:Action [
    base:desc "Optimizes heating‑period parameters to sustain target temperature while minimizing energy consumption."
    DTDFVocab:IsAutomatic true
]

// Components
instance HeatbedComponent : DTDFVocab:Component [
    base:desc "Heatbed integrated into the incubator box, controlled by heatbed actuator via MOSFET."
]

instance FanComponent : DTDFVocab:Component [
    base:desc "Fan that circulates air inside the incubator box, controlled by fan actuator."
]

instance RaspberryPiComponent : DTDFVocab:Component [
    base:desc "Raspberry Pi 4 Model B that runs the low-level driver and Python controller."
]

instance PCBComponent : DTDFVocab:Component [
    base:desc "Printed circuit board containing MOSFETs, optocouplers, and GPIO interfaces."
]

instance MOSFETComponent : DTDFVocab:Component [
    base:desc "MOSFETs used to switch heatbed and fan power via GPIO output."
]

instance OptocouplerComponent : DTDFVocab:Component [
    base:desc "Optocouplers providing isolation of the Raspberry Pi GPIO signals."
]

instance PowerSupplyComponent : DTDFVocab:Component [
    base:desc "Power supply providing electricity to incubator components."
]

// Environment
instance IncubatorEnvironment : DTDFVocab:Environment [
    base:contains HeatbedComponent, FanComponent, RaspberryPiComponent, PCBComponent, MOSFETComponent, OptocouplerComponent, PowerSupplyComponent,
                 DS18S20IntSensor1, DS18S20IntSensor2, DS18S20ExtSensor,
                 HeatbedActuator, FanActuator,
                 TemperatureSensorTelemetryMessage, TemperatureTimeSeriesData, ActuatorStateData,
                 ModelAThermal, ModelBThermal,
                 RabbitMQBroker, SciPyCalibration, PythonController,
                 MonitoringService, PredictiveSimulationService, CalibrationService, OptimizationService, ControlService,
                 CalibratedParameterValuesInsight, TemperatureNonUniformityInsight, PredictedThermalBehaviorInsight, RealTimeTemperatureInsight,
                 AdjustHeatingDutyCycleAction, AdjustFanDutyCycleAction, OptimizeEnergyConsumptionAction
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The digital twin publishes control commands (e.g., turn heatbed or fan on/off) to RabbitMQ topics. The Raspberry Pi controller subscribes to these topics, interprets the commands, and drives the heatbed and fan through the PCB and MOSFETs."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Centralized tier running on the Raspberry Pi: RabbitMQ broker, controller process, low‑level driver, and simulation models. The controller exchanges messages with the DUT via RabbitMQ and directly manipulates GPIOs through the PCB to drive the heatbed and fan."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design – specification of hardware and software interfaces; Manufacturing – assembly of styrofoam box, heatbed, fan, PCB, sensors, and Raspberry Pi; Operated – deployment in a laboratory, execution of experiments, periodic calibration of the models, and continuous monitoring and control during operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Assumptions (uniform temperature, negligible wall heat accumulation, constant specific heat, negligible fan heat) guide model construction. Calibrated parameters are obtained by minimizing residuals with SciPy’s least‑squares optimizer. Validation is performed by comparing simulated temperature trajectories against sensor data, with discrepancies reduced from ~7 °C to 6 °C when increasing fan voltage."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Message‑based communication via RabbitMQ over TCP/IP, running on the Raspberry Pi’s internal network. The controller and low‑level driver publish/subscribe to RabbitMQ topics; GPIO signals are routed through MOSFETs and optocouplers."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "The digital twin is hosted on the same Raspberry Pi 4 Model B that runs the controller, with all components (broker, controller code, models) deployed locally. The setup is open‑source and can be replicated on comparable embedded platforms."
]

instance security_and_safety_considerations : DTDFVocab:SecuritySafety [
    base:desc "A safe protocol is embedded in the low‑level driver to keep the device in a safe state; control commands are processed via RabbitMQ queues (no encryption specified). Fan and heatbed operations are monitored to prevent overheating, ensuring basic safety during operation."
]
